parameters.body:
={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are an AI configuration assistant. Extract business hours, routing rules, and emergency definitions from the provided call transcript. Output your response strictly as a JSON object."
    },
    {
      "role": "user",
      "content": "{{ $json.clean_transcript }}"
    }
  ],
  "response_format": {
    "type": "json_object"
  }
}

parameters.jsCode:
// 1. Get raw content from Groq
const rawContent = $input.first().json.choices[0].message.content;

// 2. Get the original filename from the Loop node and clean it
// This turns "demo_bens_electric.txt" into "demo_bens_electric"
const originalFileName = $node["Loop Over Items"].json.fileName;
const folderName = originalFileName.replace('.txt', '').replace('.m4a', '');

try {
  // 3. Clean and Parse Groq Output
  const cleanedJson = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
  const groqOutput = JSON.parse(cleanedJson);

  // 4. Construct Memo Structure
  const accountMemo = {
    source_file: originalFileName,
    company_name: groqOutput.company_name,
    business_hours: groqOutput.business_hours,
    routing_rules: groqOutput.routing_rules,
    emergency_definitions: groqOutput.emergency_definitions,
    questions_or_unknowns: groqOutput.questions_or_unknowns || []
  };

  // 5. Construct Agent Spec (with Prompt Hygiene)
  const agentSpec = {
    agent_name: "Clara - " + (groqOutput.company_name || folderName),
    system_prompt: `You are an assistant for ${groqOutput.company_name || folderName}. 
    BUSINESS HOURS: Greeting -> Ask purpose -> Collect name/number -> Transfer -> Fallback if fail -> Ask if anything else -> Close.
    AFTER HOURS: Greeting -> Ask purpose -> Confirm emergency -> If emergency: collect name, number, address immediately -> Transfer -> Fallback -> Ask if anything else -> Close.
    Do not mention 'function calls' to the caller.`
  };

  // 6. Return JSON (with folder_name) + Binary objects
  return {
    json: { success: true, folder_name: folderName },
    binary: {
      memo: {
        data: Buffer.from(JSON.stringify(accountMemo, null, 2)).toString('base64'),
        mimeType: 'application/json',
        fileName: 'memo.json'
      },
      spec: {
        data: Buffer.from(JSON.stringify(agentSpec, null, 2)).toString('base64'),
        mimeType: 'application/json',
        fileName: 'agent_spec.json'
      }
    }
  };

} catch (error) {
  // Fallback if LLM fails: still create files so the Write nodes don't error out
  return {
    json: { success: false, folder_name: folderName, error: error.message },
    binary: {
      memo: {
        data: Buffer.from(JSON.stringify({error: error.message, raw: rawContent})).toString('base64'),
        mimeType: 'application/json',
        fileName: 'memo.json'
      },
      spec: {
        data: Buffer.from(JSON.stringify({error: "Failed to parse"}), null, 2).toString('base64'),
        mimeType: 'application/json',
        fileName: 'agent_spec.json'
      }
    }
  };
}

let rawText = $input.first().json.transcript;

let cleanText = rawText.replace(/[\r\n]+/g, " ");

if (cleanText.length > 7000) {
    cleanText = cleanText.substring(0, 7000) + "... (truncated)";
}

return {
  clean_transcript: cleanText
};
